mapper.insert:
INSERT INTO product(
        pno
        , pClassification
        , pName
        , pPrice
        , pRegDate
        , firstThumbnail
        )
    VALUES(
        #{pno}
        , #{pClassification}
        , #{pName}
        , #{pPrice}
        , sysdate
        , #{firstThumbnail}
    )

INSERT INTO productOp(
    pOpNo
    , pno
    , pSize
    , pColor
    , pStock
)
VALUES(
    #{pOpNo}
    , #{pno}
    , #{pSize}
    , #{pColor}
    , #{pStock}
)

INSERT INTO p_thumbnail(
    thumbNo
    , pno
    , pThumbnail
)
VALUES(
    #{thumbNo}||thumb_seq.NEXTVAL
    , #{pno}
    , #{pThumbnail}
)

INSERT INTO productImg(
    pImgNo
    , pno
    , pImg
    , pImgStep
)
VALUES(
    productImg_seq.NEXTVAL
    , #{pno}
    , #{pImg}
    , #{pImgStep}
)
